example.code:
// WRONG: await fetch() inside transaction auto-closes it
const tx = db.transaction('requests', 'readwrite');
await tx.store.add(item);
await fetch('/api/sync');        // <-- auto-closes tx
await tx.done;                   // throws: transaction already finished

// Correct: complete the IDB operation first, then fetch
await db.add('requests', item);  // separate transaction per operation
await fetch('/api/sync');        // fetch after IDB is done

// Client: register one-shot sync
if ('serviceWorker' in navigator && 'sync' in ServiceWorkerRegistration.prototype) {
  const reg = await navigator.serviceWorker.ready;
  await reg.sync.register('sync-pending-requests');
}

// Service worker: handle sync
self.addEventListener('sync', (event) => {
  if (event.tag === 'sync-pending-requests') {
    event.waitUntil(replayPendingRequests());
  }
});
